def pg_points(dim,q): # projective points in F_q^dim (vector dimension dim)
    pts=[]
    for v in itertools.product(range(q), repeat=dim):
        if all(a%q==0 for a in v): continue
        for a in v:
            if a%q!=0:
                inv=pow(a,-1,q)
                pts.append(tuple((x*inv)%q for x in v))
                break
    return sorted(set(pts))
def rank_of_subset(pts, S, q):
    return rank_mod_q([pts[i] for i in S],q)
def closure_subset(pts, S, q):
    r=rank_of_subset(pts,S,q)
    return frozenset(i for i,p in enumerate(pts) if rank_mod_q([pts[j] for j in S]+[p],q)==r)
def build_pg(dim,q): # matroid rank dim
    pts=pg_points(dim,q); n=len(pts)
    # flats by closure all subsets maybe for dim4 n15 okay
    flats_by_rank=collections.defaultdict(set)
    for m in range(n+1):
        # too many
        pass
    # generate subspaces spans of subsets up to dim
    for m in range(dim+1):
        for S in itertools.combinations(range(n),m):
            cl=closure_subset(pts,S,q)
            flats_by_rank[rank_of_subset(pts,S,q)].add(cl)
    flats_by_rank={r:sorted(s, key=lambda x:(len(x),sorted(x))) for r,s in flats_by_rank.items()}
    # polarity: flat -> orthogonal complement flat
    # for a flat represented by set of points S, orth = points w with dot(v,w)=0 for all v in span(S)
    flat_perp={}
    all_flats=[F for lst in flats_by_rank.values() for F in lst]
    for F in all_flats:
        # use vectors of points in F (span)
        orth=frozenset(j for j,w in enumerate(pts) if all(sum(pts[i][a]*w[a] for a in range(dim))%q==0 for i in F))
        flat_perp[F]=orth
    return pts, flats_by_rank, flat_perp
