def transform_rank1_to_corank1(pts,q,flats_by_rank,flat_perp,x):
    n=len(pts); r=len(pts[0]); k=r-1
    # map rank3 subsets to value
    p={}
    # map flat to rank one point index for perp
    rank1_flat_to_point={F: next(iter(F)) for F in flats_by_rank[1]}
    for A in itertools.combinations(range(n),k):
        A=frozenset(A)
        if rank_of_subset(pts,A,q)==k:
            cl=closure_subset(pts,A,q)
            orth=flat_perp[cl]
            if len(orth)==0:
                # rank0
                val=0 # not for k=r-1
            else:
                point=rank1_flat_to_point[orth]
                val=x[point]
            p[A]=val
        else:
            p[A]=math.inf
    return p
def valuated_matroid_GP_ok(pts,q,p,k):
    n=len(pts)
    # GP relation: for S size k-1, T size k+1, min over i in T\S p(S∪i)+p(T-i) attained twice
    for S_tuple in itertools.combinations(range(n),k-1):
        S=set(S_tuple)
        for T_tuple in itertools.combinations(range(n),k+1):
            T=set(T_tuple)
            # Usually require S subset T? For GP, S and T arbitrary; terms i in T\S with S∪i and T-i both size k if S maybe not subset? T-i size k only if i in T and |T|=k+1; yes. S∪i size k if i not in S.
            vals=[]
            for i in T-S:
                A=frozenset(list(S)+[i])
                B=frozenset(T-{i})
                vals.append(p.get(A, math.inf)+p.get(B, math.inf))
            if vals and not min_twice_ext(vals):
                return False, ('GP', tuple(sorted(S)), tuple(sorted(T)), vals)
    return True,None
